   112→/// Stop watching the current session.
   113→#[tauri::command]
   114→pub async fn unwatch_session(state: State<'_, AppState>) -> Result<(), String> {
   115→    state.clear_watched_ongoing();
   116→    state.stop_session_watcher()
   117→}
