     8→/// A Server-Sent Event destined for browser clients.
     9→#[derive(Clone, Debug)]
    10→pub struct SseEvent {
    11→    /// Event name, e.g. "session-update" or "picker-refresh".
    12→    pub event: String,
    13→    /// JSON-serialized payload.
    14→    pub data: String,
    15→}
