    17→/// AppState holds shared state managed by Tauri.
    18→pub struct AppState {
    19→    pub session_watcher: Mutex<Option<WatcherHandle>>,
    20→    pub picker_watcher: Mutex<Option<WatcherHandle>>,
    21→    pub session_cache: Mutex<SessionCache>,
    22→    pub settings: Mutex<Settings>,
    23→    /// Ongoing status reported by the session watcher for the currently viewed session.
    24→    /// (session_path, is_ongoing) — kept in sync by the session watcher loop.
    25→    pub watched_session_ongoing: Mutex<Option<(String, bool)>>,
    26→    /// Broadcast channel for SSE — watchers send events here, HTTP clients subscribe.
    27→    pub event_tx: broadcast::Sender<SseEvent>,
    28→}
    29→
    30→impl AppState {
    31→    pub fn new() -> Self {
    32→        let (event_tx, _) = broadcast::channel(64);
    33→        Self {
    34→            session_watcher: Mutex::new(None),
    35→            picker_watcher: Mutex::new(None),
    36→            session_cache: Mutex::new(SessionCache::new()),
    37→            settings: Mutex::new(crate::settings::load_settings()),
    38→            watched_session_ongoing: Mutex::new(None),
    39→            event_tx,
    40→        }
    41→    }
    42→
    43→    /// Stop and clear the session watcher if one is running.
    44→    pub fn stop_session_watcher(&self) -> Result<(), String> {
    45→        let mut guard = self.session_watcher.lock().map_err(|e| e.to_string())?;
    46→        if let Some(handle) = guard.take() {
    47→            handle.stop();
    48→        }
    49→        Ok(())
    50→    }
    51→
    52→    /// Replace the session watcher with a new handle.
    53→    pub fn set_session_watcher(&self, handle: WatcherHandle) -> Result<(), String> {
    54→        let mut guard = self.session_watcher.lock().map_err(|e| e.to_string())?;
    55→        *guard = Some(handle);
    56→        Ok(())
    57→    }
    58→
    59→    /// Stop and clear the picker watcher if one is running.
    60→    pub fn stop_picker_watcher(&self) -> Result<(), String> {
    61→        let mut guard = self.picker_watcher.lock().map_err(|e| e.to_string())?;
    62→        if let Some(handle) = guard.take() {
    63→            handle.stop();
    64→        }
    65→        Ok(())
    66→    }
    67→
    68→    /// Replace the picker watcher with a new handle.
    69→    pub fn set_picker_watcher(&self, handle: WatcherHandle) -> Result<(), String> {
    70→        let mut guard = self.picker_watcher.lock().map_err(|e| e.to_string())?;
    71→        *guard = Some(handle);
    72→        Ok(())
    73→    }
    74→
    75→    /// Update the ongoing status for the currently watched session.
    76→    pub fn set_watched_ongoing(&self, path: String, ongoing: bool) {
    77→        if let Ok(mut guard) = self.watched_session_ongoing.lock() {
    78→            *guard = Some((path, ongoing));
    79→        }
    80→    }
    81→
    82→    /// Clear the watched session ongoing status (e.g. when unwatching).
    83→    pub fn clear_watched_ongoing(&self) {
    84→        if let Ok(mut guard) = self.watched_session_ongoing.lock() {
    85→            *guard = None;
    86→        }
    87→    }
    88→
    89→    /// Apply the session watcher's ongoing status to a list of sessions.
    90→    /// The session watcher has the most accurate ongoing detection (full chunk
    91→    /// analysis + subagent tracking), so its verdict overrides the picker's
    92→    /// lightweight metadata scan.
    93→    pub fn apply_watched_ongoing(&self, sessions: &mut [crate::parser::session::SessionInfo]) {
    94→        let guard = match self.watched_session_ongoing.lock() {
    95→            Ok(g) => g,
    96→            Err(_) => return,
    97→        };
    98→        if let Some((ref path, ongoing)) = *guard {
    99→            if let Some(s) = sessions.iter_mut().find(|s| s.path == *path) {
   100→                s.is_ongoing = ongoing;
   101→            }
   102→        }
   103→    }
   104→
   105→    /// Broadcast an SSE event to all connected browser clients.
   106→    pub fn broadcast(&self, event: &str, data: &str) {
   107→        let _ = self.event_tx.send(SseEvent {
   108→            event: event.to_string(),
   109→            data: data.to_string(),
   110→        });
   111→    }
   112→}
