    59→/// Read new lines from a session file starting at the given byte offset.
    60→/// Returns (new classified messages, updated offset, bytes read).
    61→pub fn read_session_incremental(
    62→    path: &str,
    63→    offset: u64,
    64→) -> Result<(Vec<ClassifiedMsg>, u64, u64), String> {
    65→    let f = fs::File::open(path).map_err(|e| format!("opening {path}: {e}"))?;
    66→    let mut reader = BufReader::new(f);
    67→    reader
    68→        .seek(SeekFrom::Start(offset))
    69→        .map_err(|e| format!("seeking: {e}"))?;
    70→
    71→    let mut msgs = Vec::new();
    72→    let mut bytes_read: u64 = 0;
    73→    let mut line = String::new();
    74→
    75→    loop {
    76→        line.clear();
    77→        let n = reader
    78→            .read_line(&mut line)
    79→            .map_err(|e| format!("reading: {e}"))?;
    80→        if n == 0 {
    81→            break;
    82→        }
    83→
    84→        // If the line does not end with '\n', it is a partial write at EOF
    85→        // (Claude Code v2.1.78+ streams responses line-by-line). Do not
    86→        // advance the offset past the incomplete bytes — wait for the full
    87→        // line to be flushed on the next watcher event.
    88→        if !line.ends_with('\n') {
    89→            break;
    90→        }
    91→
    92→        bytes_read += n as u64;
    93→
    94→        let trimmed = line.trim();
    95→        if trimmed.is_empty() {
    96→            continue;
    97→        }
    98→
    99→        if let Some(entry) = parse_entry(trimmed.as_bytes()) {
   100→            if let Some(msg) = classify(entry) {
   101→                msgs.push(msg);
   102→            }
   103→        }
   104→    }
   105→
   106→    Ok((msgs, offset + bytes_read, bytes_read))
   107→}
