   109→/// Return the Claude projects base directory.
   110→/// Priority: configured path > CLAUDE_PROJECTS_DIR env var > ~/.claude/projects.
   111→pub fn claude_projects_dir(configured: Option<&str>) -> Result<PathBuf, String> {
   112→    if let Some(dir) = configured {
   113→        let p = PathBuf::from(dir);
   114→        if p.exists() {
   115→            return Ok(p);
   116→        }
   117→    }
   118→    if let Ok(custom) = std::env::var("CLAUDE_PROJECTS_DIR") {
   119→        let p = PathBuf::from(&custom);
   120→        if p.exists() {
   121→            return Ok(p);
   122→        }
   123→    }
   124→    let home = dirs::home_dir().ok_or("no home directory")?;
   125→    Ok(home.join(".claude").join("projects"))
   126→}
   127→
   128→/// Return the Claude CLI projects directory for an absolute path.
   129→pub fn project_dir_for_path(abs_path: &str) -> Result<String, String> {
   130→    let base = claude_projects_dir(None)?;
   131→    let resolved = fs::canonicalize(abs_path).unwrap_or_else(|_| PathBuf::from(abs_path));
   132→    let encoded = encode_path(&resolved.to_string_lossy());
   133→    Ok(base.join(encoded).to_string_lossy().to_string())
   134→}
   135→
   136→fn encode_path(abs_path: &str) -> String {
   137→    abs_path.replace([std::path::MAIN_SEPARATOR, '/', '.', '_'], "-")
   138→}
