   219→struct PendingTool {
   220→    index: usize,
   221→    timestamp: DateTime<Utc>,
   222→}
   223→
   224→fn merge_ai_buffer(buf: &[AIMsg]) -> Chunk {
   225→    let mut texts: Vec<String> = Vec::new();
   226→    let mut thinking = 0usize;
   227→    let mut tool_calls: Vec<ToolCall> = Vec::new();
   228→    let mut model = String::new();
   229→    let mut stop = String::new();
   230→    let mut items: Vec<DisplayItem> = Vec::new();
   231→    let mut pending: HashMap<String, PendingTool> = HashMap::new();
   232→    let mut has_blocks = false;
   233→
   234→    for m in buf {
   235→        if !m.text.is_empty() {
   236→            texts.push(m.text.clone());
   237→        }
   238→        thinking += m.thinking_count;
   239→        tool_calls.extend(m.tool_calls.iter().cloned());
   240→
   241→        if model.is_empty() && !m.is_meta && !m.model.is_empty() {
   242→            model = m.model.clone();
   243→        }
   244→        if !m.is_meta && !m.stop_reason.is_empty() {
   245→            stop = m.stop_reason.clone();
   246→        }
   247→
   248→        if m.blocks.is_empty() {
   249→            continue;
   250→        }
   251→        has_blocks = true;
   252→
   253→        if !m.is_meta {
   254→            for b in &m.blocks {
   255→                match b.block_type.as_str() {
   256→                    "thinking" => {
   257→                        items.push(DisplayItem {
   258→                            item_type: DisplayItemType::Thinking,
   259→                            text: b.text.clone(),
   260→                            ..Default::default()
   261→                        });
   262→                    }
   263→                    "text" => {
   264→                        items.push(DisplayItem {
   265→                            item_type: DisplayItemType::Output,
   266→                            text: b.text.clone(),
   267→                            ..Default::default()
   268→                        });
   269→                    }
   270→                    "tool_use" => {
   271→                        let summary = tool_summary(&b.tool_name, &b.tool_input);
   272→                        let category = categorize_tool_name(&b.tool_name);
   273→                        let display_name = mcp_display_name(&b.tool_name);
   274→
   275→                        if b.tool_name == "Task" || b.tool_name == "Agent" {
   276→                            let info = extract_subagent_info(&b.tool_input);
   277→                            items.push(DisplayItem {
   278→                                item_type: DisplayItemType::Subagent,
   279→                                tool_name: b.tool_name.clone(),
   280→                                tool_id: b.tool_id.clone(),
   281→                                tool_input: b.tool_input.clone(),
   282→                                tool_summary: summary,
   283→                                tool_category: category,
   284→                                subagent_type: info.0,
   285→                                subagent_desc: info.1,
   286→                                team_member_name: info.2,
   287→                                ..Default::default()
   288→                            });
   289→                        } else {
   290→                            items.push(DisplayItem {
   291→                                item_type: DisplayItemType::ToolCall,
   292→                                tool_name: display_name,
   293→                                tool_id: b.tool_id.clone(),
   294→                                tool_input: b.tool_input.clone(),
   295→                                tool_summary: summary,
   296→                                tool_category: category,
   297→                                ..Default::default()
   298→                            });
   299→                        }
   300→                        pending.insert(
   301→                            b.tool_id.clone(),
   302→                            PendingTool {
   303→                                index: items.len() - 1,
   304→                                timestamp: m.timestamp,
   305→                            },
   306→                        );
   307→                    }
   308→                    _ => {}
   309→                }
   310→            }
   311→        } else {
   312→            for b in &m.blocks {
   313→                match b.block_type.as_str() {
   314→                    "tool_result" => {
   315→                        if let Some(p) = pending.remove(&b.tool_id) {
   316→                            items[p.index].tool_result = b.content.clone();
   317→                            items[p.index].tool_error = b.is_error;
   318→                            let dur = m.timestamp.signed_duration_since(p.timestamp);
   319→                            items[p.index].duration_ms = dur.num_milliseconds();
   320→                        } else {
   321→                            items.push(DisplayItem {
   322→                                item_type: DisplayItemType::Output,
   323→                                text: b.content.clone(),
   324→                                ..Default::default()
   325→                            });
   326→                        }
   327→                    }
   328→                    "teammate" => {
   329→                        items.push(DisplayItem {
   330→                            item_type: DisplayItemType::TeammateMessage,
   331→                            text: b.text.clone(),
   332→                            teammate_id: b.teammate_id.clone(),
   333→                            teammate_color: b.teammate_color.clone(),
   334→                            ..Default::default()
   335→                        });
   336→                    }
   337→                    "hook_event" => {
   338→                        items.push(DisplayItem {
   339→                            item_type: DisplayItemType::HookEvent,
   340→                            hook_event: b.tool_id.clone(),
   341→                            hook_name: b.tool_name.clone(),
   342→                            hook_command: b.text.clone(),
   343→                            ..Default::default()
   344→                        });
   345→                    }
   346→                    _ => {}
   347→                }
   348→            }
   349→        }
   350→    }
   351→
   352→    let first = buf.first().map(|m| m.timestamp).unwrap_or_else(Utc::now);
   353→    let last = buf.last().map(|m| m.timestamp).unwrap_or(first);
   354→    let dur = last.signed_duration_since(first).num_milliseconds();
   355→    let ts = first;
   356→
   357→    let final_items = if has_blocks {
   358→        suppress_inflated_durations(&mut items);
   359→        items
   360→    } else {
   361→        Vec::new()
   362→    };
   363→
   364→    // Usage snapshot: last non-meta assistant message's usage.
   365→    let mut usage = Usage::default();
   366→    for m in buf.iter().rev() {
   367→        if !m.is_meta && m.usage.total_tokens() > 0 {
   368→            usage = m.usage.clone();
   369→            break;
   370→        }
   371→    }
   372→
   373→    Chunk {
   374→        chunk_type: ChunkType::AI,
   375→        timestamp: ts,
   376→        model,
   377→        text: texts.join("\n"),
   378→        thinking_count: thinking,
   379→        tool_calls,
   380→        items: final_items,
   381→        usage,
   382→        stop_reason: stop,
   383→        duration_ms: dur,
   384→        ..Default::default()
   385→    }
   386→}
   387→
   388→fn suppress_inflated_durations(items: &mut [DisplayItem]) {
   389→    let max_task_dur = items
   390→        .iter()
   391→        .filter(|it| it.item_type == DisplayItemType::Subagent)
   392→        .map(|it| it.duration_ms)
   393→        .max()
   394→        .unwrap_or(0);
   395→
   396→    if max_task_dur == 0 {
   397→        return;
   398→    }
   399→
   400→    for item in items.iter_mut() {
   401→        if item.item_type == DisplayItemType::Subagent
   402→            || item.item_type == DisplayItemType::TeammateMessage
   403→        {
   404→            continue;
   405→        }
   406→        if item.duration_ms > CONCURRENT_TASK_DURATION_THRESHOLD {
   407→            item.duration_ms = 0;
   408→        }
   409→    }
   410→}
   411→
   412→/// Extract subagent info from Task tool input: (type, description, member_name)
   413→fn extract_subagent_info(input: &Option<Value>) -> (String, String, String) {
   414→    let map = match input {
   415→        Some(Value::Object(m)) => m,
   416→        _ => return (String::new(), String::new(), String::new()),
   417→    };
   418→
   419→    let subagent_type = map
   420→        .get("subagent_type")
   421→        .and_then(|v| v.as_str())
   422→        .unwrap_or("")
   423→        .to_string();
   424→    let mut description = map
   425→        .get("description")
   426→        .and_then(|v| v.as_str())
   427→        .unwrap_or("")
   428→        .to_string();
   429→    if description.is_empty() {
   430→        if let Some(prompt) = map.get("prompt").and_then(|v| v.as_str()) {
   431→            description = super::summary::truncate(prompt, 80);
   432→        }
   433→    }
   434→    let member_name = map
   435→        .get("name")
   436→        .and_then(|v| v.as_str())
   437→        .unwrap_or("")
   438→        .to_string();
   439→
   440→    (subagent_type, description, member_name)
   441→}
