   443→/// Check whether a DisplayItem is a team task (has team_name and name in input).
   444→pub fn is_team_task(item: &DisplayItem) -> bool {
   445→    match &item.tool_input {
   446→        Some(Value::Object(map)) => map.contains_key("team_name") && map.contains_key("name"),
   447→        _ => false,
   448→    }
   449→}
