     9→/// TeamTask represents a single task in a team's task board.
    10→#[derive(Debug, Clone, Serialize)]
    11→pub struct TeamTask {
    12→    pub id: String,
    13→    pub subject: String,
    14→    pub status: String,
    15→    pub owner: String,
    16→}
    17→
    18→/// TeamSnapshot represents the reconstructed state of a team.
    19→#[derive(Debug, Clone, Serialize)]
    20→pub struct TeamSnapshot {
    21→    pub name: String,
    22→    pub description: String,
    23→    pub tasks: Vec<TeamTask>,
    24→    pub members: Vec<String>,
    25→    pub member_colors: HashMap<String, String>,
    26→    pub member_ongoing: HashMap<String, bool>,
    27→    pub deleted: bool,
    28→}
    29→
    30→/// Reconstruct team task boards from chunks and worker processes.
    31→pub fn reconstruct_teams(chunks: &[Chunk], workers: &[SubagentProcess]) -> Vec<TeamSnapshot> {
    32→    let mut teams: Vec<TeamSnapshot> = Vec::new();
    33→    let mut active_idx: Option<usize> = None;
    34→    let mut task_counter = 0;
    35→
    36→    // Phase 1: Lead chunk events.
    37→    for c in chunks {
    38→        if c.chunk_type != ChunkType::AI {
    39→            continue;
    40→        }
    41→        for item in &c.items {
    42→            match (&item.item_type, item.tool_name.as_str()) {
    43→                (DisplayItemType::ToolCall, "TeamCreate") => {
    44→                    teams.push(team_snapshot_from_create(&item.tool_input));
    45→                    active_idx = Some(teams.len() - 1);
    46→                    task_counter = 0;
    47→                }
    48→                (DisplayItemType::ToolCall, "TaskCreate") if active_idx.is_some() => {
    49→                    task_counter += 1;
    50→                    let task = team_task_from_create(&item.tool_input, task_counter);
    51→                    teams[active_idx.unwrap()].tasks.push(task);
    52→                }
    53→                (DisplayItemType::ToolCall, "TaskUpdate") if active_idx.is_some() => {
    54→                    apply_team_task_update(&item.tool_input, &mut teams[active_idx.unwrap()]);
    55→                }
    56→                (DisplayItemType::ToolCall, "TeamDelete") if active_idx.is_some() => {
    57→                    teams[active_idx.unwrap()].deleted = true;
    58→                    active_idx = None;
    59→                }
    60→                (DisplayItemType::Subagent, _) if is_team_task(item) => {
    61→                    add_team_spawn_member(&item.tool_input, &mut teams);
    62→                }
    63→                _ => {}
    64→            }
    65→        }
    66→    }
    67→
    68→    // Phase 2: Worker TaskUpdate events.
    69→    for worker in workers {
    70→        let (agent_name, team_name) = split_worker_id(&worker.id);
    71→        if team_name.is_empty() {
    72→            continue;
    73→        }
    74→        if let Some(team) = find_team_by_name_mut(&mut teams, &team_name) {
    75→            apply_worker_task_updates(&worker.chunks, team, &agent_name);
    76→        }
    77→    }
    78→
    79→    // Phase 3: Populate member colors.
    80→    for team in &mut teams {
    81→        team.member_colors = HashMap::new();
    82→        team.member_ongoing = HashMap::new();
    83→    }
    84→    for worker in workers {
    85→        let (agent_name, team_name) = split_worker_id(&worker.id);
    86→        if team_name.is_empty() || worker.teammate_color.is_empty() {
    87→            continue;
    88→        }
    89→        for team in &mut teams {
    90→            if team.name == team_name {
    91→                team.member_colors
    92→                    .insert(agent_name.clone(), worker.teammate_color.clone());
    93→            }
    94→        }
    95→    }
    96→
    97→    // Phase 4: Populate member ongoing state.
    98→    for worker in workers {
    99→        let (agent_name, team_name) = split_worker_id(&worker.id);
   100→        if team_name.is_empty() {
   101→            continue;
   102→        }
   103→        if OngoingChecker::is_chunks_ongoing(&worker.chunks) {
   104→            for team in &mut teams {
   105→                if team.name == team_name {
   106→                    team.member_ongoing.insert(agent_name.clone(), true);
   107→                }
   108→            }
   109→        }
   110→    }
   111→
   112→    teams
   113→}
   114→
   115→fn team_snapshot_from_create(input: &Option<Value>) -> TeamSnapshot {
   116→    let (name, desc) = get_string_fields(input, "team_name", "description");
   117→    TeamSnapshot {
   118→        name,
   119→        description: desc,
   120→        tasks: Vec::new(),
   121→        members: Vec::new(),
   122→        member_colors: HashMap::new(),
   123→        member_ongoing: HashMap::new(),
   124→        deleted: false,
   125→    }
   126→}
   127→
   128→fn team_task_from_create(input: &Option<Value>, seq_id: i32) -> TeamTask {
   129→    let subject = get_single_field(input, "subject");
   130→    TeamTask {
   131→        id: seq_id.to_string(),
   132→        subject,
   133→        status: "pending".to_string(),
   134→        owner: String::new(),
   135→    }
   136→}
   137→
   138→fn apply_team_task_update(input: &Option<Value>, team: &mut TeamSnapshot) {
   139→    let task_id = get_single_field(input, "taskId");
   140→    if task_id.is_empty() {
   141→        return;
   142→    }
   143→    for task in &mut team.tasks {
   144→        if task.id != task_id {
   145→            continue;
   146→        }
   147→        let status = get_single_field(input, "status");
   148→        if !status.is_empty() {
   149→            task.status = status;
   150→        }
   151→        let owner = get_single_field(input, "owner");
   152→        if !owner.is_empty() {
   153→            task.owner = owner;
   154→        }
   155→        let subject = get_single_field(input, "subject");
   156→        if !subject.is_empty() {
   157→            task.subject = subject;
   158→        }
   159→        return;
   160→    }
   161→}
   162→
   163→fn add_team_spawn_member(input: &Option<Value>, teams: &mut [TeamSnapshot]) {
   164→    let (team_name, member_name) = get_string_fields(input, "team_name", "name");
   165→    if team_name.is_empty() || member_name.is_empty() {
   166→        return;
   167→    }
   168→    for team in teams.iter_mut() {
   169→        if team.name != team_name {
   170→            continue;
   171→        }
   172→        if !team.members.contains(&member_name) {
   173→            team.members.push(member_name);
   174→        }
   175→        return;
   176→    }
   177→}
   178→
   179→fn apply_worker_task_updates(chunks: &[Chunk], team: &mut TeamSnapshot, worker_name: &str) {
   180→    for c in chunks {
   181→        if c.chunk_type != ChunkType::AI {
   182→            continue;
   183→        }
   184→        for item in &c.items {
   185→            if item.item_type != DisplayItemType::ToolCall || item.tool_name != "TaskUpdate" {
   186→                continue;
   187→            }
   188→            let task_id = get_single_field(&item.tool_input, "taskId");
   189→            if task_id.is_empty() {
   190→                continue;
   191→            }
   192→            for task in &mut team.tasks {
   193→                if task.id != task_id {
   194→                    continue;
   195→                }
   196→                let status = get_single_field(&item.tool_input, "status");
   197→                if !status.is_empty() {
   198→                    task.status = status;
   199→                }
   200→                let owner = get_single_field(&item.tool_input, "owner");
   201→                if !owner.is_empty() {
   202→                    task.owner = owner;
   203→                } else if task.owner.is_empty() {
   204→                    task.owner = worker_name.to_string();
   205→                }
   206→                let subject = get_single_field(&item.tool_input, "subject");
   207→                if !subject.is_empty() {
   208→                    task.subject = subject;
   209→                }
   210→            }
   211→        }
   212→    }
   213→}
   214→
   215→fn split_worker_id(id: &str) -> (String, String) {
   216→    if let Some((agent, team)) = id.split_once('@') {
   217→        (agent.to_string(), team.to_string())
   218→    } else {
   219→        (String::new(), String::new())
   220→    }
   221→}
   222→
   223→fn find_team_by_name_mut<'a>(
   224→    teams: &'a mut [TeamSnapshot],
   225→    name: &str,
   226→) -> Option<&'a mut TeamSnapshot> {
   227→    teams.iter_mut().find(|t| t.name == name)
   228→}
   229→
   230→fn get_single_field(input: &Option<Value>, key: &str) -> String {
   231→    match input {
   232→        Some(Value::Object(map)) => map
   233→            .get(key)
   234→            .and_then(|v| v.as_str())
   235→            .unwrap_or("")
   236→            .to_string(),
   237→        _ => String::new(),
   238→    }
   239→}
   240→
   241→fn get_string_fields(input: &Option<Value>, key1: &str, key2: &str) -> (String, String) {
   242→    match input {
   243→        Some(Value::Object(map)) => {
   244→            let v1 = map
   245→                .get(key1)
   246→                .and_then(|v| v.as_str())
   247→                .unwrap_or("")
   248→                .to_string();
   249→            let v2 = map
   250→                .get(key2)
   251→                .and_then(|v| v.as_str())
   252→                .unwrap_or("")
   253→                .to_string();
   254→            (v1, v2)
   255→        }
   256→        _ => (String::new(), String::new()),
   257→    }
   258→}
