    47→            output: 5.0,
    48→            cache_read: 0.1,
    49→            cache_write: 1.25,
    50→        }
    51→    } else {
    52→        // Default to sonnet
    53→        ModelPricing {
    54→            input: 3.0,
    55→            output: 15.0,
    56→            cache_read: 0.3,
    57→            cache_write: 3.75,
    58→        }
    59→    }
    60→}
