    86→/// Estimate output tokens from assistant message content character count.
    87→/// Returns 0 if estimation is not possible.
    88→pub fn estimate_output_from_content(raw: &serde_json::Value) -> i64 {
    89→    let content = match raw.get("message").and_then(|m| m.get("content")) {
    90→        Some(c) => c,
    91→        None => return 0,
    92→    };
    93→    let arr = match content.as_array() {
    94→        Some(a) => a,
    95→        None => return 0,
    96→    };
    97→
    98→    let mut total_chars: i64 = 0;
    99→    for block in arr {
   100→        let btype = block.get("type").and_then(|v| v.as_str()).unwrap_or("");
   101→        match btype {
   102→            "text" => {
   103→                if let Some(t) = block.get("text").and_then(|v| v.as_str()) {
   104→                    total_chars += t.len() as i64;
   105→                }
   106→            }
   107→            "thinking" => {
   108→                if let Some(t) = block.get("thinking").and_then(|v| v.as_str()) {
   109→                    total_chars += t.len() as i64;
   110→                }
   111→            }
   112→            "tool_use" => {
   113→                // tool_use name + JSON input serialization
   114→                total_chars += 20; // name overhead
   115→                if let Some(input) = block.get("input") {
   116→                    total_chars += input.to_string().len() as i64;
   117→                }
   118→            }
   119→            _ => {}
   120→        }
   121→    }
   122→    // Rough estimate: ~4 characters per token for English text/code.
   123→    total_chars / 4
   124→}
