   212→/// Discover and parse subagent files for a session.
   213→pub fn discover_subagents(session_path: &str) -> Result<Vec<SubagentProcess>, String> {
   214→    let dir = Path::new(session_path).parent().unwrap_or(Path::new(""));
   215→    let base = Path::new(session_path)
   216→        .file_stem()
   217→        .and_then(|s| s.to_str())
   218→        .unwrap_or("");
   219→    let subagents_dir = dir.join(base).join("subagents");
   220→
   221→    let entries = match fs::read_dir(&subagents_dir) {
   222→        Ok(e) => e,
   223→        Err(_) => return Ok(Vec::new()),
   224→    };
   225→
   226→    let mut procs = Vec::new();
   227→
   228→    for entry in entries.flatten() {
   229→        let name = entry.file_name().to_string_lossy().to_string();
   230→        if !name.starts_with("agent-") || !name.ends_with(".jsonl") {
   231→            continue;
   232→        }
   233→
   234→        let agent_id = name
   235→            .strip_prefix("agent-")
   236→            .unwrap_or("")
   237→            .strip_suffix(".jsonl")
   238→            .unwrap_or("")
   239→            .to_string();
   240→
   241→        let file_path = subagents_dir.join(&name).to_string_lossy().to_string();
   242→
   243→        let metadata = entry.metadata().map_err(|e| e.to_string())?;
   244→        if metadata.len() == 0 {
   245→            continue;
   246→        }
   247→
   248→        if is_warmup_agent(&file_path) {
   249→            continue;
   250→        }
   251→
   252→        let session_data = read_subagent_session(&file_path)?;
   253→        if session_data.chunks.is_empty() {
   254→            continue;
   255→        }
   256→
   257→        let meta_path = subagents_dir
   258→            .join(name.replace(".jsonl", ".meta.json"))
   259→            .to_string_lossy()
   260→            .to_string();
   261→        let subagent_type = read_agent_type(&meta_path);
   262→
   263→        let mut proc = build_subagent_process(
   264→            agent_id,
   265→            file_path,
   266→            &metadata,
   267→            session_data.chunks,
   268→            subagent_type,
   269→            session_data.team_summary,
   270→            session_data.team_color,
   271→        );
   272→        proc.has_end_marker = session_data.has_end_marker;
   273→        procs.push(proc);
   274→    }
   275→
   276→    procs.sort_by(|a, b| a.start_time.cmp(&b.start_time));
