   368→/// Parsed subagent session data.
   369→struct SubagentSessionData {
   370→    chunks: Vec<Chunk>,
   371→    team_summary: String,
   372→    team_color: String,
   373→    /// True when the JSONL contains a `<synthetic>` assistant end marker.
   374→    has_end_marker: bool,
   375→}
   376→
   377→fn read_subagent_session(path: &str) -> Result<SubagentSessionData, String> {
   378→    use super::patterns::{TEAMMATE_COLOR_RE, TEAMMATE_SUMMARY_RE};
   379→
   380→    let f = fs::File::open(path).map_err(|e| format!("opening {path}: {e}"))?;
   381→    let reader = BufReader::new(f);
   382→
   383→    let mut msgs = Vec::new();
   384→    let mut team_summary = String::new();
   385→    let mut team_color = String::new();
   386→    let mut extracted_team_meta = false;
   387→    let mut has_end_marker = false;
   388→
   389→    for line_result in reader.lines() {
   390→        let line = match line_result {
   391→            Ok(l) => l,
   392→            Err(_) => break,
   393→        };
   394→
   395→        let mut entry = match parse_entry(line.as_bytes()) {
   396→            Some(e) => e,
   397→            None => continue,
   398→        };
   399→
   400→        // Detect <synthetic> assistant end marker — signals the subagent
   401→        // has definitively finished. classify() filters these out, so we
   402→        // detect them here before classification.
   403→        if entry.entry_type == "assistant" && entry.message.model == "<synthetic>" {
   404→            has_end_marker = true;
   405→        }
   406→
   407→        // Extract team metadata from first user entry.
   408→        if !extracted_team_meta && entry.entry_type == "user" {
   409→            if let Some(content) = &entry.message.content {
   410→                if let Some(s) = content.as_str() {
   411→                    if let Some(caps) = TEAMMATE_SUMMARY_RE.captures(s) {
   412→                        team_summary = caps.get(1).map_or("", |m| m.as_str()).to_string();
   413→                    }
   414→                    if let Some(caps) = TEAMMATE_COLOR_RE.captures(s) {
   415→                        team_color = caps.get(1).map_or("", |m| m.as_str()).to_string();
   416→                    }
   417→                    extracted_team_meta = true;
   418→                }
   419→            }
   420→        }
   421→
   422→        // Clear sidechain flag so classify doesn't filter.
   423→        entry.is_sidechain = false;
   424→        if let Some(msg) = classify(entry) {
   425→            msgs.push(msg);
   426→        }
   427→    }
   428→
   429→    Ok(SubagentSessionData {
   430→        chunks: build_chunks(&msgs),
   431→        team_summary,
   432→        team_color,
   433→        has_end_marker,
   434→    })
   435→}
   436→
   437→fn chunk_timing(chunks: &[Chunk]) -> (DateTime<Utc>, DateTime<Utc>, i64) {
   438→    let mut start: Option<DateTime<Utc>> = None;
   439→    let mut end: Option<DateTime<Utc>> = None;
   440→
   441→    for c in chunks {
   442→        if start.is_none() || c.timestamp < *start.as_ref().unwrap() {
   443→            start = Some(c.timestamp);
   444→        }
   445→        if end.is_none() || c.timestamp > *end.as_ref().unwrap() {
   446→            end = Some(c.timestamp);
   447→        }
   448→    }
   449→
   450→    let s = start.unwrap_or_else(Utc::now);
   451→    let e = end.unwrap_or(s);
   452→    let dur = e.signed_duration_since(s).num_milliseconds();
   453→    (s, e, dur)
   454→}
