   226→    let mut procs = Vec::new();
   227→
   228→    for entry in entries.flatten() {
   229→        let name = entry.file_name().to_string_lossy().to_string();
   230→        if !name.starts_with("agent-") || !name.ends_with(".jsonl") {
   231→            continue;
