   407→fn extract_assistant_details(content: &Option<Value>) -> (usize, Vec<ToolCall>, Vec<ContentBlock>) {
   408→    let blocks = match content {
   409→        Some(Value::Array(arr)) => arr,
   410→        _ => return (0, Vec::new(), Vec::new()),
   411→    };
   412→
   413→    let mut thinking = 0;
   414→    let mut calls = Vec::new();
   415→    let mut content_blocks = Vec::new();
   416→
   417→    for b in blocks {
   418→        let bt = b.get("type").and_then(|v| v.as_str()).unwrap_or("");
   419→        match bt {
   420→            "thinking" => {
   421→                thinking += 1;
   422→                content_blocks.push(ContentBlock {
   423→                    block_type: "thinking".to_string(),
   424→                    text: b
   425→                        .get("thinking")
   426→                        .and_then(|v| v.as_str())
   427→                        .unwrap_or("")
   428→                        .to_string(),
   429→                    ..Default::default()
   430→                });
   431→            }
   432→            "text" => {
   433→                content_blocks.push(ContentBlock {
   434→                    block_type: "text".to_string(),
   435→                    text: b
   436→                        .get("text")
   437→                        .and_then(|v| v.as_str())
   438→                        .unwrap_or("")
   439→                        .to_string(),
   440→                    ..Default::default()
   441→                });
   442→            }
   443→            "tool_use" => {
   444→                let id = b
   445→                    .get("id")
   446→                    .and_then(|v| v.as_str())
   447→                    .unwrap_or("")
   448→                    .to_string();
   449→                let name = b
   450→                    .get("name")
   451→                    .and_then(|v| v.as_str())
   452→                    .unwrap_or("")
   453→                    .to_string();
   454→                if !id.is_empty() && !name.is_empty() {
   455→                    calls.push(ToolCall {
   456→                        id: id.clone(),
   457→                        name: name.clone(),
   458→                    });
   459→                }
   460→                content_blocks.push(ContentBlock {
   461→                    block_type: "tool_use".to_string(),
   462→                    tool_id: id,
   463→                    tool_name: name,
   464→                    tool_input: b.get("input").cloned(),
   465→                    ..Default::default()
   466→                });
   467→            }
   468→            _ => {
   469→                content_blocks.push(ContentBlock {
   470→                    block_type: bt.to_string(),
   471→                    text: b
   472→                        .get("text")
   473→                        .and_then(|v| v.as_str())
   474→                        .unwrap_or("")
   475→                        .to_string(),
   476→                    ..Default::default()
   477→                });
   478→            }
   479→        }
   480→    }
   481→
   482→    (thinking, calls, content_blocks)
   483→}
