   291→/// Convert chunks to display messages (port of Go chunksToMessages).
   292→pub fn chunks_to_messages(
   293→    chunks: &[Chunk],
   294→    subagents: &[SubagentProcess],
   295→    color_by_tool_id: &HashMap<String, String>,
   296→) -> Vec<DisplayMessage> {
   297→    let mut msgs = Vec::new();
   298→    let mut pool_idx: usize = 0;
   299→
   300→    for c in chunks {
   301→        match c.chunk_type {
   302→            ChunkType::User => {
   303→                msgs.push(DisplayMessage {
   304→                    role: "user".to_string(),
   305→                    model: String::new(),
   306→                    content: c.user_text.clone(),
   307→                    timestamp: format_time(&c.timestamp),
   308→                    thinking_count: 0,
   309→                    tool_call_count: 0,
   310→                    output_count: 0,
   311→                    tokens_raw: 0,
   312→                    input_tokens: 0,
   313→                    output_tokens: 0,
   314→                    cache_read_tokens: 0,
   315→                    cache_creation_tokens: 0,
   316→                    context_tokens: 0,
   317→                    duration_ms: 0,
   318→                    items: Vec::new(),
   319→                    last_output: None,
   320→                    is_error: false,
   321→                    teammate_spawns: 0,
   322→                    teammate_messages: 0,
   323→                    subagent_label: String::new(),
   324→                });
   325→            }
   326→            ChunkType::AI => {
   327→                let mut team_spawns = 0;
   328→                let mut teammate_ids: HashSet<String> = HashSet::new();
   329→                for it in &c.items {
   330→                    if it.item_type == DisplayItemType::Subagent && is_team_task(it) {
   331→                        team_spawns += 1;
   332→                    }
   333→                    if it.item_type == DisplayItemType::TeammateMessage
   334→                        && !it.teammate_id.is_empty()
   335→                    {
   336→                        teammate_ids.insert(it.teammate_id.clone());
   337→                    }
   338→                }
   339→
   340→                let lo = find_last_output(&c.items);
   341→                let frontend_lo = lo.as_ref().map(convert_last_output);
   342→
   343→                msgs.push(DisplayMessage {
   344→                    role: "claude".to_string(),
   345→                    model: short_model(&c.model),
   346→                    content: c.text.clone(),
   347→                    timestamp: format_time(&c.timestamp),
   348→                    thinking_count: c.thinking_count,
   349→                    tool_call_count: c.tool_calls.len(),
   350→                    output_count: count_output_items(&c.items),
   351→                    tokens_raw: c.usage.total_tokens(),
   352→                    input_tokens: c.usage.input_tokens,
   353→                    output_tokens: c.usage.output_tokens,
   354→                    cache_read_tokens: c.usage.cache_read_tokens,
   355→                    cache_creation_tokens: c.usage.cache_creation_tokens,
   356→                    context_tokens: c.usage.input_tokens
   357→                        + c.usage.cache_read_tokens
   358→                        + c.usage.cache_creation_tokens,
   359→                    duration_ms: c.duration_ms,
   360→                    items: convert_display_items(
   361→                        &c.items,
   362→                        subagents,
   363→                        color_by_tool_id,
   364→                        &mut pool_idx,
   365→                    ),
   366→                    last_output: frontend_lo,
   367→                    is_error: false,
   368→                    teammate_spawns: team_spawns,
   369→                    teammate_messages: teammate_ids.len(),
   370→                    subagent_label: String::new(),
   371→                });
   372→            }
   373→            ChunkType::System => {
   374→                msgs.push(DisplayMessage {
   375→                    role: "system".to_string(),
   376→                    model: String::new(),
   377→                    content: c.output.clone(),
   378→                    timestamp: format_time(&c.timestamp),
   379→                    thinking_count: 0,
   380→                    tool_call_count: 0,
   381→                    output_count: 0,
   382→                    tokens_raw: 0,
   383→                    input_tokens: 0,
   384→                    output_tokens: 0,
   385→                    cache_read_tokens: 0,
   386→                    cache_creation_tokens: 0,
   387→                    context_tokens: 0,
   388→                    duration_ms: 0,
   389→                    items: Vec::new(),
   390→                    last_output: None,
   391→                    is_error: c.is_error,
   392→                    teammate_spawns: 0,
   393→                    teammate_messages: 0,
   394→                    subagent_label: String::new(),
   395→                });
   396→            }
   397→            ChunkType::Compact => {
   398→                msgs.push(DisplayMessage {
   399→                    role: "compact".to_string(),
   400→                    model: String::new(),
   401→                    content: c.output.clone(),
   402→                    timestamp: format_time(&c.timestamp),
   403→                    thinking_count: 0,
