    match c {
        ToolCategory::Read => "Read",
        ToolCategory::Edit => "Edit",
        ToolCategory::Write => "Write",
        ToolCategory::Bash => "Bash",
        ToolCategory::Grep => "Grep",
        ToolCategory::Glob => "Glob",
        ToolCategory::Task => "Task",
        ToolCategory::Tool => "Tool",
