    #[test]
    fn display_item_type_str_all_variants() {
        assert_eq!(
            display_item_type_str(&DisplayItemType::Thinking),
            "Thinking"
        );
        assert_eq!(display_item_type_str(&DisplayItemType::Output), "Output");
        assert_eq!(
